+
+        let event = WebhookEvent::new("e1", "push", "github").with_headers(headers);
+
+        assert_eq!(event.header("x-github-event"), Some("push"));
+        assert_eq!(event.header("X-GITHUB-EVENT"), Some("push"));
+        assert_eq!(event.header("X-GitHub-Event"), Some("push"));
+        assert_eq!(event.header("nonexistent"), None);
+    }
