+        let statuses = vec![
+            (DeliveryStatus::Pending, "\"pending\""),
+            (DeliveryStatus::Delivered, "\"delivered\""),
+            (DeliveryStatus::Failed, "\"failed\""),
+            (DeliveryStatus::DeadLettered, "\"dead_lettered\""),
+        ];
